#include <iostream>
#include <vector>
#include <omp.h>

void scan(const std::vector<int>& input, std::vector<int>& output) {
    int n = input.size();
    output[0] = 0;

    #pragma omp parallel for
    for (int i = 1; i < n; i++) {
        int sum = 0;
        for (int j = 0; j < i; j++) {
            sum += input[j];
        }
        output[i] = sum;
    }
}

int main() {
    int n;
    std::cin >> n;

    std::vector<int> input(n);
    for (int i = 0; i < n; i++) {
        std::cin >> input[i];
    }

    std::vector<int> output(n);
    scan(input, output);

    for (int i = 0; i < n; i++) {
        std::cout << output[i] << std::endl;
    }

    return 0;
}
